INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000011', 'stressful-situations1', 'daily')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0007-000000000001', 'en', 1, 'user', 'Hi, I''m calling about a kettle I purchased last week. I''m afraid it''s defective.', 'Xin chào, tôi gọi về cái ấm đun tôi mua tuần trước. Nó có vẻ bị lỗi.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 2, 'partner', 'I''m sorry to hear that. Can you describe the problem for me?', 'Tôi tiếc khi nghe điều đó. Bạn có thể mô tả vấn đề không?'),
  ('00000000-0000-0000-0007-000000000001', 'en', 3, 'user', 'The lid doesn''t seal properly and hot water leaks when I pour. It''s a safety hazard.', 'Nắp không đóng kín và nước nóng bị rò khi rót. Đây là nguy hiểm an toàn.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 4, 'partner', 'I see. Do you have your receipt or order number?', 'Tôi hiểu. Bạn có hóa đơn hoặc số đơn hàng không?'),
  ('00000000-0000-0000-0007-000000000001', 'en', 5, 'user', 'Yes. The order number is KT-two-zero-two-five-dash-four-four-one.', 'Có. Số đơn hàng là KT-2025-441.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 6, 'partner', 'Thank you. I can offer you a replacement unit.', 'Cảm ơn. Tôi có thể đổi cho bạn một sản phẩm mới.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 7, 'user', 'I''d prefer a full refund, actually. I''ve lost confidence in the product and I''d like my money back.', 'Thực ra tôi muốn được hoàn tiền đầy đủ. Tôi đã mất niềm tin vào sản phẩm và muốn lấy lại tiền.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 8, 'partner', 'I understand, but our policy is to offer an exchange for faulty items.', 'Tôi hiểu, nhưng chính sách của chúng tôi là đổi sản phẩm cho hàng lỗi.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 9, 'user', 'I appreciate that, but a leaking kettle is a safety issue, not just a defect. I''m entitled to a refund under consumer law.', 'Tôi hiểu, nhưng ấm bị rò nước là vấn đề an toàn, không chỉ là lỗi thông thường. Tôi có quyền hoàn tiền theo luật bảo vệ người tiêu dùng.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 10, 'partner', 'Let me speak with my supervisor about this. Could you hold for a moment?', 'Để tôi nói chuyện với cấp trên về việc này. Bạn có thể giữ máy một chút không?'),
  ('00000000-0000-0000-0007-000000000001', 'en', 11, 'partner', 'Thank you for holding. We''ll process a full refund to your original payment method within three to five business days.', 'Cảm ơn đã chờ. Chúng tôi sẽ hoàn tiền đầy đủ về phương thức thanh toán ban đầu trong 3–5 ngày làm việc.'),
  ('00000000-0000-0000-0007-000000000001', 'en', 12, 'user', 'Thank you. I appreciate you resolving this. I do hope this gets flagged as a quality issue internally.', 'Cảm ơn. Tôi đánh giá cao việc bạn giải quyết vấn đề. Tôi hy vọng điều này được ghi nhận là vấn đề chất lượng nội bộ.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0007-000000000002', 'ja', 1, 'user', '先週御社のケトルを購入したのですが、不具合があって連絡させていただきました。', 'Tôi đã mua ấm đun của quý công ty tuần trước, và liên hệ vì nó có vấn đề.', 'せんしゅうおんしゃのケトルをこうにゅうしたのですが、ふぐあいがあってれんらくさせていただきました。', 'Senshū on-sha no ketoru wo kōnyū shita no desu ga, fuguai ga atte renraku sasete itadakimashita.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 2, 'partner', 'それは大変失礼いたしました。どのような不具合でしょうか？', 'Thật xin lỗi vì sự bất tiện. Vấn đề cụ thể là gì?', 'それはたいへんしつれいいたしました。どのようなふぐあいでしょうか？', 'Sore wa taihen shitsurei itashimashita. Dono yō na fuguai deshō ka?'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 3, 'user', 'ふたがきちんと閉まらず、お湯を注ぐ際に漏れてしまいます。安全上の問題があります。', 'Nắp không đóng kín và nước nóng bị rò khi rót. Có vấn đề về an toàn.', 'ふたがきちんとしまらず、おゆをそそぐさいにもれてしまいます。あんぜんじょうのもんだいがあります。', 'Futa ga kichinto shimarazu, o-yu wo sosogu sai ni morete shimaimasu. Anzen-jō no mondai ga arimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 4, 'partner', 'ご確認ありがとうございます。レシートまたはご注文番号はお手元にありますか？', 'Cảm ơn đã cho biết. Bạn có hóa đơn hoặc số đơn hàng không?', 'ごかくにんありがとうございます。レシートまたはごちゅうもんばんごうはおてもとにありますか？', 'Go-kakunin arigatō gozaimasu. Reshīto mata wa go-chūmon-bangō wa o-temoto ni arimasu ka?'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 5, 'user', 'はい。注文番号はKT-2025-441です。', 'Có. Số đơn hàng là KT-2025-441.', 'はい。ちゅうもんばんごうはKT-2025-441です。', 'Hai. Chūmon-bangō wa KT-nī-zero-nī-go-yon-yon-ichi desu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 6, 'partner', 'ありがとうございます。新しい商品と交換させていただきます。', 'Cảm ơn. Chúng tôi sẽ đổi sản phẩm mới cho bạn.', 'ありがとうございます。あたらしいしょうひんとこうかんさせていただきます。', 'Arigatō gozaimasu. Atarashii shōhin to kōkan sasete itadakimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 7, 'user', 'できれば返金していただきたいのですが。商品への信頼を失いましたので、購入代金を返していただきたいです。', 'Nếu được tôi muốn hoàn tiền. Tôi đã mất niềm tin vào sản phẩm và muốn lấy lại tiền.', 'できればへんきんしていただきたいのですが。しょうひんへのしんらいをうしないましたので、こうにゅうだいきんをかえしていただきたいです。', 'Dekireba henkin shite itadakitai no desu ga. Shōhin e no shinrai wo ushina imashita node, kōnyū daikin wo kaeshite itadakitai desu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 8, 'partner', 'ご不便をおかけして申し訳ございません。ただ、弊社の規定では不良品の場合は交換対応となっております。', 'Xin lỗi vì sự bất tiện. Tuy nhiên, chính sách của chúng tôi là đổi sản phẩm cho hàng lỗi.', 'ごふべんをおかけしてもうしわけございません。ただ、へいしゃのきていではふりょうひんのばあいはこうかんたいおうとなっております。', 'Go-fuben wo o-kake shite mōshiwake gozaimasen. Tada, heisha no kitei de wa furyō-hin no baai wa kōkan taiō to natte orimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 9, 'user', 'お気持ちはわかります。ただ、お湯が漏れるのは安全上の問題ですので、消費者法に基づき返金を請求する権利があると思います。', 'Tôi hiểu. Nhưng ấm bị rò nước là vấn đề an toàn, nên tôi nghĩ mình có quyền yêu cầu hoàn tiền theo luật bảo vệ người tiêu dùng.', 'おきもちはわかります。ただ、おゆがもれるのはあんぜんじょうのもんだいですので、しょうひしゃほうにもとづきへんきんをせいきゅうするけんりがあるとおもいます。', 'O-kimochi wa wakarimasu. Tada, o-yu ga moreru no wa anzen-jō no mondai desu node, shōhisha-hō ni motozuki henkin wo seikyū suru kenri ga aru to omoimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 10, 'partner', '少々お待ちください。上の者に確認いたします。', 'Xin chờ một chút. Tôi sẽ xác nhận với cấp trên.', 'しょうしょうおまちください。うえのものにかくにんいたします。', 'Shōshō o-machi kudasai. Ue no mono ni kakunin itashimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 11, 'partner', 'お待たせいたしました。全額ご返金させていただきます。元のお支払い方法に3〜5営業日以内に返金いたします。', 'Cảm ơn đã chờ. Chúng tôi sẽ hoàn tiền đầy đủ. Tiền sẽ được trả về phương thức thanh toán ban đầu trong 3–5 ngày làm việc.', 'おまたせいたしました。ぜんがくごへんきんさせていただきます。もとのおしはらいほうほうにさんからごえいぎょうびいないにへんきんいたします。', 'O-matase itashimashita. Zengaku go-henkin sasete itadakimasu. Moto no o-shiharai hōhō ni san kara go eigyō-bi inai ni henkin itashimasu.'),
  ('00000000-0000-0000-0007-000000000002', 'ja', 12, 'user', 'ありがとうございます。ご対応いただき助かりました。品質の問題として社内でご共有いただければ幸いです。', 'Cảm ơn. Tôi rất biết ơn sự hỗ trợ. Hy vọng vấn đề này được ghi nhận là vấn đề chất lượng nội bộ.', 'ありがとうございます。ごたいおういただきたすかりました。ひんしつのもんだいとしてしゃないでごきょうゆういただければさいわいです。', 'Arigatō gozaimasu. Go-taiō itadaki tasukarimashita. Hinshitsu no mondai to shite shanai de go-kyōyū itadakereba saiwai desu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000012', 'stressful-situations2', 'daily')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0007-000000000003', 'en', 1, 'partner', 'I think we should go with the cheaper supplier. It would save us about twenty percent.', 'Tôi nghĩ chúng ta nên chọn nhà cung cấp rẻ hơn. Sẽ tiết kiệm khoảng 20%.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 2, 'user', 'I see your point, but I''m not sure that''s the right call in this case.', 'Tôi hiểu ý bạn, nhưng tôi không chắc đó là quyết định đúng trong trường hợp này.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 3, 'partner', 'Why not? The cost savings are pretty significant.', 'Tại sao không? Tiết kiệm chi phí khá đáng kể đấy.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 4, 'user', 'You''re right about the savings. My concern, though, is quality — their reviews are quite mixed.', 'Bạn đúng về tiết kiệm. Nhưng lo ngại của tôi là chất lượng — đánh giá của họ khá lẫn lộn.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 5, 'partner', 'We can manage quality issues as they come up.', 'Chúng ta có thể xử lý vấn đề chất lượng khi nó xảy ra.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 6, 'user', 'With respect, I''d rather avoid the problem than manage it. A quality issue could cost us more in the long run.', 'Tôi kính trọng ý kiến, nhưng tôi muốn ngăn ngừa vấn đề hơn là xử lý nó. Vấn đề chất lượng có thể tốn kém hơn về lâu dài.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 7, 'partner', 'That seems overly cautious to me.', 'Với tôi điều đó có vẻ quá thận trọng.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 8, 'user', 'I understand we see this differently. Could we agree to request samples from both suppliers first?', 'Tôi hiểu chúng ta có quan điểm khác nhau. Chúng ta có thể đồng ý yêu cầu mẫu từ cả hai nhà cung cấp trước không?'),
  ('00000000-0000-0000-0007-000000000003', 'en', 9, 'partner', 'That would take time.', 'Điều đó sẽ mất thời gian.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 10, 'user', 'It would — about two weeks. But it gives us solid data to base the decision on. I think it''s worth it.', 'Đúng — khoảng 2 tuần. Nhưng nó cho chúng ta dữ liệu chắc chắn để ra quyết định. Tôi nghĩ điều đó xứng đáng.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 11, 'partner', 'Fair enough. I can see the logic. Let''s do it.', 'Đúng thôi. Tôi thấy logic đó. Hãy làm vậy.'),
  ('00000000-0000-0000-0007-000000000003', 'en', 12, 'user', 'Great. I''ll arrange the sample requests this afternoon. Thanks for hearing me out.', 'Tuyệt. Tôi sẽ sắp xếp yêu cầu mẫu chiều nay. Cảm ơn đã lắng nghe.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0007-000000000004', 'ja', 1, 'partner', '安い方のサプライヤーを選ぶべきだと思います。コストが約20%削減できます。', 'Tôi nghĩ nên chọn nhà cung cấp rẻ hơn. Chi phí có thể giảm khoảng 20%.', 'やすいほうのサプライヤーをえらぶべきだとおもいます。コストがやくにじゅっぱーせんとさくげんできます。', 'Yasui hō no sapuraiyā wo erabu beki da to omoimasu. Kosuto ga yaku ni-jū-pāsento sakugen dekimasu.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 2, 'user', 'おっしゃることはわかります。ただ、この場合はそれが最善ではないかもしれないと思っています。', 'Tôi hiểu ý bạn. Nhưng tôi nghĩ trong trường hợp này đó có thể không phải là lựa chọn tốt nhất.', 'おっしゃることはわかります。ただ、このばあいはそれがさいぜんではないかもしれないとおもっています。', 'Ossharu koto wa wakarimasu. Tada, kono baai wa sore ga saizen de wa nai kamo shirenai to omotte imasu.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 3, 'partner', 'なぜですか？コスト削減は大きいですよ。', 'Tại sao vậy? Tiết kiệm chi phí là đáng kể đấy.', 'なぜですか？コストさくげんはおおきいですよ。', 'Naze desu ka? Kosuto sakugen wa ōkii desu yo.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 4, 'user', 'コスト削減の点はおっしゃる通りです。ただ、私が気になるのは品質です。レビューがまちまちなんです。', 'Điểm tiết kiệm chi phí bạn nói đúng. Nhưng điều tôi lo là chất lượng. Đánh giá của họ khá lẫn lộn.', 'コストさくげんのてんはおっしゃるとおりです。ただ、わたしがきになるのはひんしつです。レビューがまちまちなんです。', 'Kosuto sakugen no ten wa ossharu tōri desu. Tada, watashi ga ki ni naru no wa hinshitsu desu. Rebyū ga machimachi nan desu.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 5, 'partner', '品質の問題が起きたら、そのときに対応すればいいじゃないですか。', 'Nếu xảy ra vấn đề chất lượng thì xử lý lúc đó không sao mà.', 'ひんしつのもんだいがおきたら、そのときにたいおうすればいいじゃないですか。', 'Hinshitsu no mondai ga okitara, sono toki ni taiō sureba ii ja nai desu ka.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 6, 'user', 'お気持ちはわかりますが、問題が起きてから対応するより、最初から防ぐ方がよいと思います。品質問題は長期的に見るとコスト増につながりかねません。', 'Tôi hiểu suy nghĩ của bạn, nhưng tôi nghĩ tốt hơn là ngăn ngừa từ đầu thay vì xử lý sau. Vấn đề chất lượng có thể dẫn đến tăng chi phí về lâu dài.', 'おきもちはわかりますが、もんだいがおきてからたいおうするより、さいしょからふせぐほうがよいとおもいます。ひんしつもんだいはちょうきてきにみるとコストぞうにつながりかねません。', 'O-kimochi wa wakarimasu ga, mondai ga okite kara taiō suru yori, saisho kara fusegu hō ga yoi to omoimasu. Hinshitsu mondai wa chōki-teki ni miru to kosuto-zō ni tsunagari kanemasen.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 7, 'partner', 'それは少し慎重すぎるのではないでしょうか。', 'Có lẽ điều đó hơi quá thận trọng không?', 'それはすこししんちょうすぎるのではないでしょうか。', 'Sore wa sukoshi shinchō sugiru no de wa nai deshō ka.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 8, 'user', '見解が違うことはわかります。ひとまず両方のサプライヤーにサンプルを請求して比較してみるのはいかがでしょうか。', 'Tôi hiểu chúng ta có quan điểm khác nhau. Hay là trước tiên yêu cầu mẫu từ cả hai nhà cung cấp để so sánh?', 'けんかいがちがうことはわかります。ひとまずりょうほうのサプライヤーにサンプルをせいきゅうしてひかくしてみるのはいかがでしょうか。', 'Kenkai ga chigau koto wa wakarimasu. Hitomazu ryōhō no sapuraiyā ni sanpuru wo seikyū shite hikaku shite miru no wa ikaga deshō ka.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 9, 'partner', 'それには時間がかかりますね。', 'Điều đó sẽ mất thời gian.', 'それにはじかんがかかりますね。', 'Sore ni wa jikan ga kakarimasu ne.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 10, 'user', '確かに2週間ほどかかります。ただ、データに基づいて判断できるようになりますので、その価値はあると思います。', 'Đúng, khoảng 2 tuần. Nhưng chúng ta có thể ra quyết định dựa trên dữ liệu, nên tôi nghĩ điều đó xứng đáng.', 'たしかにふたしゅうかんほどかかります。ただ、データにもとづいてはんだんできるようになりますので、そのかちはあるとおもいます。', 'Tashika ni futa-shūkan hodo kakarimasu. Tada, dēta ni motozuite handan dekiru yō ni narimasu node, sono kachi wa aru to omoimasu.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 11, 'partner', 'なるほど。理屈はわかりました。そうしましょう。', 'Tôi hiểu rồi. Logic đó có lý. Hãy làm vậy.', 'なるほど。りくつはわかりました。そうしましょう。', 'Naruhodo. Rikutsu wa wakarimashita. Sō shimashō.'),
  ('00000000-0000-0000-0007-000000000004', 'ja', 12, 'user', 'ありがとうございます。今日の午後にサンプルを請求します。意見を聞いてくれてありがとうございます。', 'Cảm ơn. Tôi sẽ yêu cầu mẫu chiều nay. Cảm ơn đã lắng nghe.', 'ありがとうございます。きょうのごごにサンプルをせいきゅうします。いけんをきいてくれてありがとうございます。', 'Arigatō gozaimasu. Kyō no gogo ni sanpuru wo seikyū shimasu. Iken wo kiite kurete arigatō gozaimasu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000013', 'stressful-situations3', 'daily')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0007-000000000005', 'en', 1, 'user', 'Excuse me, I''ve been waiting at the carousel for forty minutes and my bag hasn''t come out.', 'Xin lỗi, tôi đã chờ ở băng chuyền 40 phút và túi của tôi vẫn chưa ra.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 2, 'partner', 'I''m very sorry about that. May I have your flight number and boarding pass?', 'Tôi rất xin lỗi. Tôi có thể xem số chuyến bay và thẻ lên máy bay của bạn không?'),
  ('00000000-0000-0000-0007-000000000005', 'en', 3, 'user', 'It''s VA-four-five-two from Singapore. Here''s my boarding pass.', 'Chuyến VA-452 từ Singapore. Đây là thẻ lên máy bay của tôi.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 4, 'partner', 'Thank you. Could you describe your luggage for me?', 'Cảm ơn. Bạn có thể mô tả hành lý của bạn không?'),
  ('00000000-0000-0000-0007-000000000005', 'en', 5, 'user', 'It''s a large hard-shell case, dark navy blue, with a yellow luggage tag on the handle.', 'Một vali cứng lớn, xanh navy đậm, có thẻ hành lý màu vàng trên tay cầm.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 6, 'partner', 'Let me check our system... It looks like your bag may have missed the connecting flight in Singapore.', 'Để tôi kiểm tra hệ thống... Có vẻ như túi của bạn có thể đã bỏ lỡ chuyến bay kết nối ở Singapore.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 7, 'user', 'It''s in Singapore? That''s a big problem — I have a meeting tomorrow morning.', 'Nó ở Singapore à? Đó là vấn đề lớn — tôi có cuộc họp sáng mai.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 8, 'partner', 'I sincerely apologize. We''ll put your bag on the next available flight. It should arrive by tomorrow evening.', 'Tôi thành thật xin lỗi. Chúng tôi sẽ đưa túi của bạn lên chuyến bay gần nhất có thể. Nó sẽ đến vào tối mai.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 9, 'user', 'Tomorrow evening? I''ll need some essentials for tonight and tomorrow. Can you help with that?', 'Tối mai? Tôi sẽ cần một số đồ thiết yếu cho tối nay và ngày mai. Bạn có thể hỗ trợ không?'),
  ('00000000-0000-0000-0007-000000000005', 'en', 10, 'partner', 'Yes — we can provide a toiletry kit and up to one hundred dollars for emergency clothing purchases.', 'Có — chúng tôi có thể cung cấp túi vệ sinh và đến 100 đô để mua quần áo khẩn cấp.'),
  ('00000000-0000-0000-0007-000000000005', 'en', 11, 'user', 'Okay. And how will I know when the bag arrives?', 'Được. Tôi sẽ biết khi nào túi đến như thế nào?'),
  ('00000000-0000-0000-0007-000000000005', 'en', 12, 'partner', 'We''ll call and text you. Here''s your reference number: LH-three-seven-nine-two. I''m sorry again for the inconvenience.', 'Chúng tôi sẽ gọi và nhắn tin cho bạn. Đây là số tham chiếu: LH-3792. Tôi thành thật xin lỗi vì sự bất tiện.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0007-000000000006', 'ja', 1, 'user', 'すみません、40分ほど待っているのですが、私の荷物がターンテーブルから出てきません。', 'Xin lỗi, tôi đã chờ khoảng 40 phút nhưng hành lý của tôi vẫn chưa ra ở băng chuyền.', 'すみません、よんじゅっぷんほどまっているのですが、わたしのにもつがターンテーブルからでてきません。', 'Sumimasen, yonjuppun hodo matte iru no desu ga, watashi no nimotsu ga tān tēburu kara dete kimasen.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 2, 'partner', '大変申し訳ございません。便名と搭乗券をお持ちでしょうか？', 'Thành thật xin lỗi. Bạn có số chuyến bay và thẻ lên máy bay không?', 'たいへんもうしわけございません。びんめいととうじょうけんをおもちでしょうか？', 'Taihen mōshiwake gozaimasen. Bin-mei to tōjō-ken wo o-mochi deshō ka?'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 3, 'user', 'シンガポール発のVA-452便です。搭乗券はこちらです。', 'Chuyến VA-452 từ Singapore. Đây là thẻ lên máy bay.', 'シンガポールはつのVA-452びんです。とうじょうけんはこちらです。', 'Shingapōru hatsu no VA-yon-go-nī bin desu. Tōjō-ken wa kochira desu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 4, 'partner', 'ありがとうございます。お荷物の特徴をお聞かせいただけますか？', 'Cảm ơn. Bạn có thể mô tả đặc điểm hành lý không?', 'ありがとうございます。おにもつのとくちょうをおきかせいただけますか？', 'Arigatō gozaimasu. O-nimotsu no tokuchō wo o-kikase itadakemasu ka?'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 5, 'user', '大きいハードケースで、濃いネイビーブルーです。ハンドルに黄色いタグがついています。', 'Vali cứng lớn, màu xanh navy đậm. Có thẻ màu vàng trên tay cầm.', 'おおきいハードケースで、こいネイビーブルーです。ハンドルにきいろいタグがついています。', 'Ōkii hādo kēsu de, koi neibī burū desu. Handoru ni kiiroi tagu ga tsuite imasu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 6, 'partner', 'ただいまシステムを確認いたします…シンガポールでの乗り継ぎ便に積み込まれなかった可能性がございます。', 'Tôi kiểm tra hệ thống ngay... Có khả năng hành lý không được xếp lên chuyến kết nối ở Singapore.', 'ただいまシステムをかくにんいたします…シンガポールでののりつぎびんにつみこまれなかったかのうせいがございます。', 'Tadaima shisutemu wo kakunin itashimasu... Shingapōru de no noritsugi-bin ni tsumikoma renakatta kanōsei ga gozaimasu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 7, 'user', 'シンガポールにあるんですか？明日の朝に会議があるので、非常に困ります。', 'Nó ở Singapore à? Sáng mai tôi có cuộc họp, điều này rất bất tiện.', 'シンガポールにあるんですか？あしたのあさにかいぎがあるので、ひじょうにこまります。', 'Shingapōru ni aru n desu ka? Ashita no asa ni kaigi ga aru node, hijō ni komarimasu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 8, 'partner', '誠に申し訳ございません。次の便でお届けできるよう手配いたします。明日の夜には届く予定です。', 'Thành thật xin lỗi. Chúng tôi sẽ sắp xếp giao qua chuyến bay gần nhất. Dự kiến đến vào tối mai.', 'まことにもうしわけございません。つぎのびんでおとどけできるようてはいいたします。あしたのよるにはとどくよていです。', 'Makoto ni mōshiwake gozaimasen. Tsugi no bin de o-todoke dekiru yō ni tehai itashimasu. Ashita no yoru ni wa todoku yotei desu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 9, 'user', '明日の夜ですか。今夜と明日に必要なものがあるのですが、サポートしていただけますか？', 'Tối mai à. Tôi cần một số đồ cho tối nay và ngày mai, bạn có thể hỗ trợ không?', 'あしたのよるですか。こんやとあしたにひつようなものがあるのですが、サポートしていただけますか？', 'Ashita no yoru desu ka. Konya to ashita ni hitsuyō na mono ga aru no desu ga, sapōto shite itadakemasu ka?'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 10, 'partner', 'はい。洗面用具セットと、緊急の衣類購入のために最大10,000円のバウチャーをご提供できます。', 'Có. Chúng tôi có thể cung cấp bộ đồ vệ sinh và phiếu mua quần áo khẩn cấp tối đa 10.000 yên.', 'はい。せんめんようぐセットと、きんきゅうのいるいこうにゅうのためにさいだいいちまんえんのバウチャーをごていきょうできます。', 'Hai. Senmen-yōgu setto to, kinkyū no irui kōnyū no tame ni saidai ichi-man-en no bauchā wo go-teikyō dekimasu.'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 11, 'user', 'わかりました。荷物が届いたらどう知らせてもらえますか？', 'Hiểu rồi. Làm sao tôi biết khi hành lý đến?', 'わかりました。にもつがとどいたらどうしらせてもらえますか？', 'Wakarimashita. Nimotsu ga todaitara dō shirasete moraemasu ka?'),
  ('00000000-0000-0000-0007-000000000006', 'ja', 12, 'partner', 'お電話とSMSでご連絡いたします。受付番号はLH-3792でございます。改めてご迷惑をおかけして大変申し訳ございません。', 'Chúng tôi sẽ gọi và nhắn tin cho bạn. Số tiếp nhận là LH-3792. Một lần nữa xin thành thật xin lỗi vì sự bất tiện.', 'おでんわとSMSでごれんらくいたします。うけつけばんごうはLH-3792でございます。あらためてごめいわくをおかけしてたいへんもうしわけございません。', 'O-denwa to SMS de go-renraku itashimasu. Uketsuke-bangō wa LH-san-nana-kyū-ni de gozaimasu. Aratamete go-meiwaku wo o-kake shite taihen mōshiwake gozaimasen.');
INSERT INTO scenario_groups (id, slug, category) VALUES
