INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0007-000000000007', 'en', 1, 'partner', 'So, Minh — what''s your biggest weakness? And how have you addressed it?', 'Vậy Minh — điểm yếu lớn nhất của bạn là gì? Và bạn đã giải quyết nó như thế nào?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 2, 'user', 'That''s a great question. Could I take a moment to think before I answer?', 'Đó là câu hỏi hay. Tôi có thể suy nghĩ một chút trước khi trả lời không?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 3, 'partner', 'Of course, take your time.', 'Tất nhiên, cứ từ từ.'),
  ('00000000-0000-0000-0007-000000000007', 'en', 4, 'user', 'Thank you. I''d say I''ve sometimes struggled with delegating. I tend to want to handle things myself.', 'Cảm ơn. Tôi nghĩ tôi đôi khi gặp khó khăn với việc giao việc. Tôi có xu hướng muốn tự xử lý mọi thứ.'),
  ('00000000-0000-0000-0007-000000000007', 'en', 5, 'partner', 'How has that affected your team?', 'Điều đó ảnh hưởng đến nhóm của bạn như thế nào?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 6, 'user', 'Sorry — could you clarify what you mean? Are you asking about team dynamics generally, or a specific incident?', 'Xin lỗi — bạn có thể làm rõ không? Bạn hỏi về động lực nhóm nói chung, hay một sự kiện cụ thể?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 7, 'partner', 'I mean, did it slow things down for the team?', 'Ý tôi là, nó có làm chậm tiến độ nhóm không?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 8, 'user', 'In the early stages of my career, yes. Once I recognised it, I actively worked on changing that.', 'Trong giai đoạn đầu sự nghiệp, có. Khi nhận ra, tôi đã tích cực thay đổi.'),
  ('00000000-0000-0000-0007-000000000007', 'en', 9, 'partner', 'What specifically did you do about it?', 'Cụ thể bạn đã làm gì để thay đổi?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 10, 'user', 'Let me think for a second — I want to give you an accurate answer. I started weekly check-ins with my team and practised giving clear handoffs.', 'Cho tôi nghĩ một chút — tôi muốn đưa ra câu trả lời chính xác. Tôi bắt đầu họp kiểm tra hàng tuần với nhóm và tập giao việc rõ ràng hơn.'),
  ('00000000-0000-0000-0007-000000000007', 'en', 11, 'partner', 'And did that make a difference?', 'Và điều đó có tạo ra sự khác biệt không?'),
  ('00000000-0000-0000-0007-000000000007', 'en', 12, 'user', 'Significantly. In my last role, team output increased by around twenty percent after I made those changes. It was a real turning point for me.', 'Đáng kể. Ở công việc trước, năng suất nhóm tăng khoảng 20% sau khi tôi thực hiện những thay đổi đó. Đó là bước ngoặt thực sự với tôi.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0007-000000000008', 'ja', 1, 'partner', 'ミンさん、あなたの一番の弱点は何ですか？そして、それをどう改善してきましたか？', 'Minh-san, điểm yếu lớn nhất của bạn là gì? Và bạn đã cải thiện nó như thế nào?', 'ミンさん、あなたのいちばんのじゃくてんはなんですか？そして、それをどうかいぜんしてきましたか？', 'Min-san, anata no ichiban no jakuten wa nan desu ka? Soshite, sore wo dō kaizen shite kimashita ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 2, 'user', 'いい質問ですね。お答えする前に少し考える時間をいただいてもよいでしょうか？', 'Câu hỏi hay. Tôi có thể xin ít thời gian suy nghĩ trước khi trả lời không?', 'いいしつもんですね。おこたえするまえにすこしかんがえるじかんをいただいてもよいでしょうか？', 'Ii shitsumon desu ne. O-kotae suru mae ni sukoshi kangaeru jikan wo itadaite mo yoi deshō ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 3, 'partner', 'もちろんです。どうぞ。', 'Tất nhiên. Cứ tự nhiên.', 'もちろんです。どうぞ。', 'Mochiron desu. Dōzo.'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 4, 'user', 'ありがとうございます。仕事を人に任せることが苦手だったと思います。なんでも自分でやってしまう傾向がありました。', 'Cảm ơn. Tôi nghĩ tôi đã gặp khó khăn với việc giao việc cho người khác. Tôi có xu hướng muốn tự làm mọi thứ.', 'ありがとうございます。しごとをひとにまかせることがにがてだったとおもいます。なんでもじぶんでやってしまうけいこうがありました。', 'Arigatō gozaimasu. Shigoto wo hito ni makaseru koto ga nigate datta to omoimasu. Nandemo jibun de yatte shimau keikō ga arimashita.'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 5, 'partner', 'それはチームにどのような影響を与えましたか？', 'Điều đó ảnh hưởng đến nhóm như thế nào?', 'それはチームにどのようなえいきょうをあたえましたか？', 'Sore wa chīmu ni dono yō na eikyō wo ataemashita ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 6, 'user', 'すみません、少し確認させてください。過去のチーム全体のことをお聞きですか、それとも具体的なエピソードでしょうか？', 'Xin lỗi, cho tôi xác nhận một chút. Bạn hỏi về toàn bộ nhóm trong quá khứ, hay một sự kiện cụ thể?', 'すみません、すこしかくにんさせてください。かこのチームぜんたいのことをおききですか、それともぐたいてきなエピソードでしょうか？', 'Sumimasen, sukoshi kakunin sasete kudasai. Kako no chīmu zentai no koto wo o-kiki desu ka, soretomo gutaiteki na episōdo deshō ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 7, 'partner', 'チームの仕事が遅くなったりしましたか？', 'Nó có làm chậm tiến độ nhóm không?', 'チームのしごとがおそくなったりしましたか？', 'Chīmu no shigoto ga osoku nattari shimashita ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 8, 'user', 'キャリアの初期段階では、そうなったことがあります。自覚してからは、積極的に改善するよう努めてきました。', 'Trong giai đoạn đầu sự nghiệp, có. Khi nhận ra, tôi đã tích cực cố gắng cải thiện.', 'キャリアのしょきだんかいでは、そうなったことがあります。じかくしてからは、せっきょくてきにかいぜんするようつとめてきました。', 'Kyaria no shoki dankai de wa, sō natta koto ga arimasu. Jikaku shite kara wa, sekkyoku-teki ni kaizen suru yō tsutomete kimashita.'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 9, 'partner', '具体的にはどのようなことをしましたか？', 'Cụ thể bạn đã làm gì?', 'ぐたいてきにはどのようなことをしましたか？', 'Gutaiteki ni wa dono yō na koto wo shimashita ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 10, 'user', '正確にお伝えしたいので、少し考えてもよいでしょうか。チームとの週次確認を始め、仕事の引き継ぎを明確にするよう意識しました。', 'Tôi muốn trả lời chính xác, cho tôi nghĩ thêm chút nhé. Tôi bắt đầu kiểm tra hàng tuần với nhóm và chú ý làm rõ việc bàn giao công việc.', 'せいかくにおつたえしたいので、すこしかんがえてもよいでしょうか。チームとのしゅうじかくにんをはじめ、しごとのひきつぎをめいかくにするよういしきしました。', 'Seikaku ni o-tsutae shitai node, sukoshi kangaete mo yoi deshō ka. Chīmu to no shū-ji kakunin wo hajime, shigoto no hikitsugi wo meikaku ni suru yō ishiki shimashita.'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 11, 'partner', 'それで改善されましたか？', 'Điều đó có cải thiện không?', 'それでかいぜんされましたか？', 'Sore de kaizen saremashita ka?'),
  ('00000000-0000-0000-0007-000000000008', 'ja', 12, 'user', 'はい、大きく改善されました。前職では、その変化の後、チームのアウトプットが約20%向上しました。私にとって大きな転機になりました。', 'Vâng, cải thiện đáng kể. Ở công việc trước, sau những thay đổi đó, năng suất nhóm tăng khoảng 20%. Đó là bước ngoặt lớn với tôi.', 'はい、おおきくかいぜんされました。ぜんしょくでは、そのへんかのあと、チームのアウトプットがやくにじゅっぱーせんとこうじょうしました。わたしにとっておおきなてんきになりました。', 'Hai, ōkiku kaizen saremashita. Zenshoku de wa, sono henka no ato, chīmu no autoputto ga yaku ni-jū-pāsento kōjō shimashita. Watashi ni totte ōkina tenki ni narimashita.');
